from functools import lru_cache
class Solution:
    def scoreOfStudents(self, s, answers):
        nums = []
        ops = []
        for ch in s:
            if ch.isdigit():
                nums.append(int(ch))
            else:
                ops.append(ch)
        n = len(nums)
        stack = [nums[0]]
        for idx, op in enumerate(ops):
            if op == '*':
                stack[-1] *= nums[idx + 1]
            else:
                stack.append(nums[idx + 1])
        correct = sum(stack)
        @lru_cache(maxsize=None)
        def all_values(i, j):
            if i == j:
                return frozenset([nums[i]])
            vals = set()
            for k in range(i, j):
                left = all_values(i, k)
                right = all_values(k + 1, j)
                op = ops[k]
                for a in left:
                    for b in right:
                        v = a + b if op == '+' else a * b
                        if v <= 10 ** 9:
                            vals.add(v)
            return frozenset(vals)
        possible = set(v for v in all_values(0, n - 1) if v <= 1000)
        all_values.cache_clear()
        total = 0
        for ans in answers:
            if ans == correct:
                total += 5
            elif ans in possible:
                total += 2
        return total

