var scoreOfStudents = function(s, answers) {
    const nums = [];
    const ops = [];
    for (const ch of s) {
        if (ch >= '0' && ch <= '9') nums.push(Number(ch));
        else ops.push(ch);
    }
    const n = nums.length;
    let stack = [nums[0]];
    for (let idx = 0; idx < ops.length; idx++) {
        if (ops[idx] === '*') {
            stack[stack.length - 1] *= nums[idx + 1];
        } else {
            stack.push(nums[idx + 1]);
        }
    }
    const correct = stack.reduce((a, b) => a + b, 0);
    const dp = Array.from({length: n}, () => Array.from({length: n}, () => new Set()));
    for (let i = 0; i < n; i++) dp[i][i] = new Set([nums[i]]);
    for (let length = 2; length <= n; length++) {
        for (let i = 0; i + length - 1 < n; i++) {
            const j = i + length - 1;
            const vals = new Set();
            for (let k = i; k < j; k++) {
                const op = ops[k];
                for (const a of dp[i][k]) {
                    for (const b of dp[k + 1][j]) {
                        const v = op === '+' ? a + b : a * b;
                        if (v <= 1000) vals.add(v);
                    }
                }
            }
            dp[i][j] = vals;
        }
    }
    const possible = dp[0][n - 1];
    let total = 0;
    for (const ans of answers) {
        if (ans === correct) total += 5;
        else if (possible.has(ans)) total += 2;
    }
    return total;
};
